106	// Allow runs the pre-claim hook and applies the two-strikes retry policy.
107	func (g *PreClaimGuard) Allow(ctx context.Context, beadID string) (bool, string) {
108		if g == nil || g.hook == nil {
109			return true, ""
110		}
111		err, timedOut := callPreClaimHookWithTimeout(ctx, g.hook, g.timeout)
112		if err != nil || timedOut {
113			switch classifyPreClaimError(err) {
114			case preClaimClassTrackerContention:
115				reason := err.Error()
116				g.mu.Lock()
117				shouldLog := !g.loggedSystemic[reason]
118				g.loggedSystemic[reason] = true
119				g.mu.Unlock()
120				if shouldLog && g.log != nil {
121					_, _ = fmt.Fprintf(g.log, "pre-claim hook: %v (transient tracker-file contention; leaving beads untouched)\n", err)
122				}
123				return false, TrackerContentionPreClaimReasonPrefix + reason
124			case preClaimClassSystemic:
125				reason := err.Error()
126				g.mu.Lock()
127				shouldLog := !g.loggedSystemic[reason]
128				g.loggedSystemic[reason] = true
129				g.mu.Unlock()
130				if shouldLog && g.log != nil {
131					_, _ = fmt.Fprintf(g.log, "pre-claim hook: %v (systemic; leaving beads untouched)\n", err)
132				}
133				return false, SystemicPreClaimReasonPrefix + reason
134			}
135	
136			g.mu.Lock()
137			defer g.mu.Unlock()
138	
139			g.failCounts[beadID]++
140			if g.failCounts[beadID] >= 2 {
141				if g.store != nil {
142					until := g.now().UTC().Add(g.cooldown)
143					detail := "pre-claim hook failed"
144					if err != nil {
145						detail = err.Error()
146					} else if timedOut {
147						detail = fmt.Sprintf("pre-claim hook timed out after %s", g.timeout)
148					}
149					_ = g.store.SetExecutionCooldown(beadID, until, "preclaim-hook-failed", detail, "")
150				}
151			}
152			if g.log != nil {
153				switch {
154				case timedOut:
155					_, _ = fmt.Fprintf(g.log, "pre-claim hook timed out after %s (skipping %s)\n", g.timeout, beadID)
156				case err != nil:
157					_, _ = fmt.Fprintf(g.log, "pre-claim hook: %v (skipping %s)\n", err, beadID)
158				}
159			}
160			if timedOut {
161				return false, fmt.Sprintf("pre-claim hook timed out after %s", g.timeout)
162			}
163			return false, err.Error()
164		}
165	
166		g.mu.Lock()
167		delete(g.failCounts, beadID)
168		g.mu.Unlock()
169		return true, ""
170	}
