188	// classifyPreClaimError categorizes a pre-claim hook error. Systemic and
189	// tracker-contention classes both idle the worker without cooldowning the bead
190	// (no bead is at fault); they differ only in the reason code surfaced to
191	// operators. Anything else is treated as bead-specific and runs through the
192	// two-strikes cooldown policy.
193	func classifyPreClaimError(err error) preClaimClass {
194		if err == nil {
195			return preClaimClassBeadSpecific
196		}
197		msg := err.Error()
198		// Staged tracker-file contention: a landing-worktree "staged changes" error
199		// whose staged paths are exclusively DDx-managed tracker/metadata files.
200		// Another worker's tracker commit is partially staged; the index settles
201		// within milliseconds. Treating this as bead-specific would wrongly cooldown
202		// beads during a transient multi-worker commit race (ddx-df77e668).
203		if isStagedTrackerContentionError(msg) {
204			return preClaimClassTrackerContention
205		}
206		// Branch divergence: local tracker has diverged from origin.
207		if strings.Contains(msg, "local branch ") && strings.Contains(msg, " has diverged from origin ") {
208			return preClaimClassSystemic
209		}
210		// Staged changes that include code/doc/test files: real work was never
211		// committed. This is a systemic repo state, not a transient contention.
212		if strings.Contains(msg, "staged changes") {
213			return preClaimClassSystemic
214		}
215		// Git index.lock: an external git process holds the index lock. This is
216		// transient (sub-second for normal operations); no bead is at fault.
217		if strings.Contains(msg, "index.lock") {
218			return preClaimClassSystemic
219		}
220		// Corrupt landing indexes are repo-health failures, not bead-specific
221		// failures. Surface once as systemic so the worker can auto-repair or ask
222		// for operator intervention without cooldowning beads.
223		if strings.Contains(msg, "index file smaller than expected") ||
224			strings.Contains(msg, "repairing landing worktree index") {
225			return preClaimClassSystemic
226		}
227		return preClaimClassBeadSpecific
228	}
