230	// isStagedTrackerContentionError reports whether a "landing worktree has staged
231	// changes" error lists only DDx-managed tracker/metadata files. A mixed or
232	// code-only staged set is NOT tracker contention (it is systemic).
233	func isStagedTrackerContentionError(msg string) bool {
234		if !strings.Contains(msg, "staged changes after waiting") {
235			return false
236		}
237		paths := stagedPathsFromError(msg)
238		if len(paths) == 0 {
239			return false
240		}
241		for _, p := range paths {
242			if !isTrackerMetadataPath(p) {
243				return false
244			}
245		}
246		return true
247	}
