275	// isTrackerMetadataPath reports whether a repo-relative path is one of the
276	// DDx-managed tracker/metadata files (see trackerMetadataPaths).
277	func isTrackerMetadataPath(path string) bool {
278		clean := strings.TrimSpace(strings.ReplaceAll(path, "\\", "/"))
279		if clean == "" {
280			return false
281		}
282		for _, managed := range trackerMetadataPaths {
283			m := strings.TrimSuffix(managed, "/")
284			if clean == m || strings.HasPrefix(clean, m+"/") {
285				return true
286			}
287		}
288		return false
289	}
